export const allServices = [...maleServices, ...femaleServices];

export function getServicesByGender(gender: 'MALE' | 'FEMALE'): Service[] {
  return gender === 'MALE' ? maleServices : femaleServices;
}

export function getServicesByGenderAndCategory(gender: 'MALE' | 'FEMALE', category: string): Service[] {
  return getServicesByGender(gender).filter(s => s.category === category);
}

export function getServicesByGenderCategoryAndSubCategory(gender: 'MALE' | 'FEMALE', category: string, subCategory: string): Service[] {
  return getServicesByGenderAndCategory(gender, category).filter(s => s.subCategory === subCategory);
}

export function getSubCategories(gender: 'MALE' | 'FEMALE', category: string): string[] {
  const services = getServicesByGenderAndCategory(gender, category);
  return [...new Set(services.map(s => s.subCategory))];
}
